# ============================================================================
# Load approved plugin hashes from a secured file
# ============================================================================
sub load_approved_hashes {
    my ($hash_file) = @_;
    %APPROVED_PLUGIN_HASHES = ();

    unless (-f $hash_file) {
        warn "WARNING: Approved hashes file not found: $hash_file\n";
        warn "WARNING: No plugins will be loaded without approved hashes.\n";
        return;
    }

    # Check file permissions - should only be writable by owner
    my @stat = stat($hash_file);
    my $mode = $stat[2] & 07777;
    if ($mode & 0022) {
        die "SECURITY ERROR: Approved hashes file $hash_file is group/world writable (mode: " 
            . sprintf("%04o", $mode) . "). Fix permissions first.\n";
    }

    open my $fh, '<', $hash_file
        or die "Cannot open approved hashes file $hash_file: $!\n";

    while (my $line = <$fh>) {
        chomp $line;
        $line =~ s/#.*//;          # strip comments
        $line =~ s/^\s+|\s+$//g;   # trim whitespace
        next unless $line;

        if ($line =~ /^([a-f0-9]{64})\s+(.+)$/) {
            $APPROVED_PLUGIN_HASHES{$2} = $1;
        } else {
            warn "Ignoring malformed line in hashes file: $line\n";
        }
    }
    close $fh;

    my $count = scalar keys %APPROVED_PLUGIN_HASHES;
    print "Loaded $count approved plugin hash(es).\n";
}

