sub check_file_permissions {
    my ($filepath) = @_;

    my @stat = stat($filepath);
    unless (@stat) {
        warn "Cannot stat file: $filepath: $!\n";
        return 0;
    }

    my $mode = $stat[2] & 07777;

    # File should not be world-writable
    if ($mode & 0002) {
        warn "SECURITY: Plugin file $filepath is world-writable (mode: "
            . sprintf("%04o", $mode) . ")\n";
        return 0;
    }

    # File should not be group-writable
    if ($mode & 0020) {
        warn "SECURITY: Plugin file $filepath is group-writable (mode: "
            . sprintf("%04o", $mode) . ")\n";
        return 0;
    }

    return 1;
}

# ============================================================================
