            log_info  => sub { main::plugin_log('INFO',  '$plugin_name', \@_) },
            log_warn  => sub { main::plugin_log('WARN',  '$plugin_name', \@_) },
            log_error => sub { main::plugin_log('ERROR', '$plugin_name', \@_) },
            get_config => sub { main::plugin_get_config('$plugin_name', \@_) },
        };

        sub get_api { return \$plugin_api }

        $plugin_code

        1;
    };

