sub execute_plugin {
    my ($plugin_name, $function, @args) = @_;

    unless (exists $LOADED_PLUGINS{$plugin_name}) {
        warn "Plugin '$plugin_name' is not loaded.\n";
        return undef;
    }

    my $package = $LOADED_PLUGINS{$plugin_name}{package};
    my $full_function = "${package}::${function}";

    # Check if the function exists
    no strict 'refs';
    unless (defined &{$full_function}) {
        warn "Function '$function' not found in plugin '$plugin_name'.\n";
        return undef;
    }

    # Execute with timeout and error handling
    my $result;
    my $error;

    local $SIG{ALRM} = sub { die "Plugin execution timeout\n" };
    alarm(10);  # 10 second timeout

    eval {
        $result = &{$full_function}(@args);
    };
    $error = $@;

    alarm(0);  # Cancel alarm

    if ($error) {
        warn "ERROR: Plugin '$plugin_name' function '$function' failed: $error\n";
        return undef;
    }

    return $result;
}

